customEChartConfig:
{{ ((chartType) => ( 
(() => {

  const rawData = getRevenueByTime.data;

  // ดึงเวลาไม่ซ้ำ
  const xAxisData = [...new Set(
    rawData.map(item => String(item.timeLabel))
  )];

  // group ตาม series
  const grouped = {};

  rawData.forEach(item => {

    const name = item.seriesName;

    if (!grouped[name]) {
      grouped[name] = {};
    }

    grouped[name][item.timeLabel] = Number(item.totalAmount);

  });

  return {
    tooltip: {
      trigger: 'axis'
    },

    legend: {
      top: 0
    },

    xAxis: {
      type: 'category',
      data: xAxisData
    },

    yAxis: {
      type: 'value'
    },

    series: Object.keys(grouped).map(name => ({
      name,
      type: 'line',
      smooth: true,
      data: xAxisData.map(time =>
        grouped[name][time] || 0
      )
    }))
  };

})()
))(HistoricalRevenue.chartType) }}
